"use client";

import Link from "next/link";
import { BlogPost, getRecentBlogs, getBlogsByCategory } from "@/lib/blogs";
import { use } from "react";

interface BlogDetailClientProps {
  blog: BlogPost;
}

export default function BlogDetailClient({ blog }: BlogDetailClientProps) {
  const relatedBlogs = getBlogsByCategory(blog.category).filter(b => b.id !== blog.id).slice(0, 3);
  const recentBlogs = getRecentBlogs(4).filter(b => b.id !== blog.id);

  return (
    <div style={{ padding: "2rem 0", minHeight: "calc(100vh - 68px)" }}>
      <div className="container">
        <div style={{ maxWidth: "800px", margin: "0 auto" }}>
          <Link
            href="/blogs"
            style={{
              display: "inline-flex",
              alignItems: "center",
              gap: "0.375rem",
              color: "var(--primary)",
              textDecoration: "none",
              fontWeight: 500,
              marginBottom: "1.5rem",
            }}
          >
            <svg width="16" height="16" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7" />
            </svg>
            Quay lại danh sách bài viết
          </Link>

          <div style={{ marginBottom: "1rem" }}>
            <span
              style={{
                fontSize: "0.75rem",
                fontWeight: 600,
                color: "var(--primary)",
                background: "var(--primary-light)",
                padding: "0.375rem 0.75rem",
                borderRadius: "4px",
                textTransform: "uppercase",
              }}
            >
              {getCategoryLabel(blog.category)}
            </span>
          </div>

          <h1 style={{ fontSize: "2.25rem", fontWeight: 800, lineHeight: 1.3, marginBottom: "1.5rem" }}>
            {blog.title}
          </h1>

          <div style={{ display: "flex", alignItems: "center", gap: "1.5rem", marginBottom: "2rem", color: "var(--text-muted)", fontSize: "0.9375rem" }}>
            <span style={{ display: "flex", alignItems: "center", gap: "0.375rem" }}>
              <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
              </svg>
              {blog.author}
            </span>
            <span style={{ display: "flex", alignItems: "center", gap: "0.375rem" }}>
              <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
              </svg>
              {formatDate(blog.createdAt)}
            </span>
            <span style={{ display: "flex", alignItems: "center", gap: "0.375rem" }}>
              <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                <path strokeLinecap="round" strokeLinejoin="round" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
              </svg>
              {blog.viewCount.toLocaleString()} lượt xem
            </span>
          </div>

          <div style={{ borderRadius: "16px", overflow: "hidden", marginBottom: "2.5rem" }}>
            <img
              src={blog.coverImage}
              alt={blog.title}
              style={{ width: "100%", height: "auto", maxHeight: "450px", objectFit: "cover" }}
            />
          </div>

          <div
            style={{
              fontSize: "1.0625rem",
              lineHeight: 1.8,
              color: "var(--text)",
            }}
            dangerouslySetInnerHTML={{ __html: blog.content }}
          />

          <div style={{ marginTop: "2.5rem", padding: "1.5rem", background: "var(--bg-card)", borderRadius: "12px", border: "1.5px solid var(--border)" }}>
            <h4 style={{ fontSize: "1rem", fontWeight: 700, marginBottom: "1rem" }}>Tags:</h4>
            <div style={{ display: "flex", gap: "0.5rem", flexWrap: "wrap" }}>
              {blog.tags.map((tag) => (
                <span
                  key={tag}
                  style={{
                    fontSize: "0.8125rem",
                    padding: "0.375rem 0.75rem",
                    background: "var(--bg)",
                    borderRadius: "20px",
                    color: "var(--text-muted)",
                  }}
                >
                  #{tag}
                </span>
              ))}
            </div>
          </div>

          {relatedBlogs.length > 0 && (
            <div style={{ marginTop: "3rem" }}>
              <h3 style={{ fontSize: "1.5rem", fontWeight: 700, marginBottom: "1.5rem" }}>Bài viết liên quan</h3>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(240px, 1fr))", gap: "1rem" }}>
                {relatedBlogs.map((related) => (
                  <Link
                    key={related.id}
                    href={`/blogs/${related.slug}`}
                    style={{
                      display: "block",
                      background: "var(--bg-card)",
                      borderRadius: "12px",
                      overflow: "hidden",
                      textDecoration: "none",
                      border: "1.5px solid var(--border)",
                      transition: "all 0.2s ease",
                    }}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.transform = "translateY(-2px)";
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.transform = "translateY(0)";
                    }}
                  >
                    <div style={{ height: "120px", overflow: "hidden" }}>
                      <img
                        src={related.coverImage}
                        alt={related.title}
                        style={{ width: "100%", height: "100%", objectFit: "cover" }}
                      />
                    </div>
                    <div style={{ padding: "1rem" }}>
                      <h4 style={{ fontSize: "0.9375rem", fontWeight: 600, color: "var(--text)", lineHeight: 1.4, display: "-webkit-box", WebkitLineClamp: 2, WebkitBoxOrient: "vertical", overflow: "hidden" }}>
                        {related.title}
                      </h4>
                    </div>
                  </Link>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

function getCategoryLabel(category: string): string {
  const labels: Record<string, string> = {
    career: "Sự nghiệp",
    interview: "Phỏng vấn",
    salary: "Lương",
  };
  return labels[category] || category;
}

function formatDate(dateString: string): string {
  const date = new Date(dateString);
  return date.toLocaleDateString("vi-VN", { day: "numeric", month: "long", year: "numeric" });
}
